module top_module(
   input clk,
   input rst,
   input enable,
   output reg [3:0] out
);reg [3:0] obf_count;
reg [3:0] next_count;

always @ (posedge clk) begin
   if (rst) begin
      obf_count <= 4'b0;
   end else begin
      obf_count <= next_count;
   end
end

always @ (*) begin
   if (enable) begin
      next_count = obf_count + 4'b1;
   end else begin
      next_count = obf_count;
   end
end

assign out = obf_count;

endmodule
